// Mappt /internal/asm/targets Response auf einen Eintrag pro Domain.
// Erwartet: { targets: [{user_id, domain, email, plan}], count: N }
// Output: ein item pro verifizierter Domain.

const items = $input.all();
const out = [];

for (const item of items) {
  const body = item.json || {};
  const targets = Array.isArray(body.targets) ? body.targets : [];
  for (const t of targets) {
    const d = (t && typeof t.domain === 'string') ? t.domain.trim().toLowerCase() : '';
    if (!d || d.length > 253) continue;
    if (!/^[a-z0-9.\-]+$/.test(d)) continue;  // strikte Domain-Whitelist
    out.push({ json: { domain: d, user_id: t.user_id || null } });
  }
}

if (out.length === 0) {
  // Fail-safe: kein Output stoppt den Cron-Lauf — Diff-Node bekäme leere Liste.
  // Wir loggen das implizit indem wir trotzdem ein Sentinel-Item liefern, aber
  // ohne domain wird der nächste Schritt es per Validierung verwerfen.
  return [];
}
return out;

// Diff-Logik: vergleicht aktuelle crt.sh-Ergebnisse mit Stand vom letzten Lauf.
// Speichert Stand in workflowStaticData (n8n-eigene Persistenz pro Workflow).

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
staticData.knownSubdomains = staticData.knownSubdomains || {};

const out = [];

for (const item of items) {
  const domain = item.json.domain || '';
  let raw = item.json;
  // crt.sh returnt Array — bei Fehler dict mit error
  let entries = Array.isArray(raw) ? raw : (Array.isArray(raw.body) ? raw.body : []);
  if (!Array.isArray(entries)) entries = [];

  const found = new Set();
  for (const entry of entries) {
    if (!entry || typeof entry !== 'object') continue;
    const nv = (entry.name_value || '').toString();
    for (const cand of nv.split('\n')) {
      let c = cand.trim().toLowerCase().replace(/^\*\.?/, '').replace(/\.+$/, '');
      if (!c || c.length > 253) continue;
      if (c !== domain && !c.endsWith('.' + domain)) continue;
      if (c.includes('*') || c.includes('..')) continue;
      if (!/^[a-z0-9.\-]+$/.test(c)) continue;
      found.add(c);
    }
  }

  const known = new Set(staticData.knownSubdomains[domain] || []);
  const novel = [...found].filter(s => !known.has(s));

  // Update static state (alle aktuellen) — neue beim naechsten Lauf nicht mehr 'novel'
  staticData.knownSubdomains[domain] = [...found].sort();
  staticData.lastRunAt = new Date().toISOString();

  out.push({
    json: {
      domain,
      total_known: found.size,
      novel_count: novel.length,
      novel_subdomains: novel.slice(0, 20),
      checked_at: new Date().toISOString()
    }
  });
}

return out;

